const express = require('express');
const bodyParser = require('body-parser');
const { Client } = require('@elastic/elasticsearch');

const app = express();
app.use(bodyParser.json());

const esClient = new Client({
  node: 'http://localhost:9200',
});

// Define a function to build Elasticsearch Query DSL
function buildQuery(params) {
  const query = {};

  if (params.query) {
    query.match = { [params.index]: params.query };
  }

  if (params.fields) {
    query.fields = params.fields;
  }

  if (params.sort) {
    query.sort = [{ [params.sort.field]: params.sort.order }];
  }

  return query;
}

// Define a function to build script_score query
function buildScriptScoreQuery(script) {
  const scriptScore = {};

  if (script.lang === 'painless') {
    scriptScore.script = {
      source: script.source,
      lang: script.lang,
    };
  } else if (script.lang === 'groovy') {
    scriptScore.script = {
      source: script.source,
      lang: script.lang,
    };
  }

  return scriptScore;
}

// Define a function to execute Elasticsearch query
async function executeQuery(index, params) {
  const query = buildQuery(params);
  const scriptScoreQuery = buildScriptScoreQuery(params.script);

  if (scriptScoreQuery) {
    query.script_score = scriptScoreQuery;
  }

  try {
    const result = await esClient.search({
      index,
      body: { query },
    });

    return result.hits.hits;
  } catch (error) {
    console.error(error);
    throw error;
  }
}

// Define API endpoint for search
app.post('/search', async (req, res) => {
  try {
    const params = req.body;
    const index = 'my_index'; // Replace with your actual index name

    const result = await executeQuery(index, params);

    res.json(result);
  } catch (error) {
    console.error(error);
    res.status(500).json({ message: 'Internal Server Error' });
  }
});

